```csharp
public class Dyr
{
    public string Navn;
    public Dyr(string navn) => Navn = navn;
    public virtual void Beskriv() => Console.WriteLine($"Dyr: {Navn}");
}

public class Hund : Dyr
{
    public string Rase;

    public Hund(string navn, string rase) : base(navn) // kall base-ctor
    {
        Rase = rase;
    }

    public override void Beskriv()
    {
        base.Beskriv();                               // kall base-metode
        Console.WriteLine($"Rase: {Rase}");
    }
}
```

```csharp
public class Base
{
    public virtual void Hilsen() => Console.WriteLine("Hei fra Base");
}
public class Sub : Base
{
    public new void Hilsen() => Console.WriteLine("Hei fra Sub");
}

Base b = new Sub();
b.Hilsen();  // "Hei fra Base" (skjuling = base sin versjon brukes)

Sub s = new Sub();
s.Hilsen();  // "Hei fra Sub" (riktig type-referanse)
```

