```csharp
public abstract class Form
{
    public string Farge = "rød"; // vanlig felt

    public abstract double Areal(); // må implementeres
    public abstract double Omkrets();

    public void VisFarge() => Console.WriteLine(Farge); // vanlig metode
}

public class Sirkel : Form
{
    private double r;
    public Sirkel(double r) => this.r = r;
    public override double Areal() => Math.PI * r * r;
    public override double Omkrets() => 2 * Math.PI * r;
}
```

