// Abstrakt klasse – felles base med delt kode
public abstract class Form
{
    public string Farge { get; set; }  // delt kode
    public abstract double Areal();    // kontrakt
}

// Interface – ren kontrakt
public interface ITegnbar
{
    void Tegn();
}

// Klassen får både delvis implementasjon OG kontrakt
public class Sirkel : Form, ITegnbar
{
    public override double Areal() => Math.PI * 25;
    public void Tegn() => Console.WriteLine("Tegner sirkel");
}
```

